#include <stdlib.h>
#include <stdio.h>
#include <math.h>
#include <cuda_runtime.h>
#include <sys/time.h>

// Inline definitions from main.h to avoid missing header issues
#define fp double
#define NUMBER_PAR_PER_BOX 100
#define DOT(A,B) ((A.x)*(B.x)+(A.y)*(B.y)+(A.z)*(B.z))

typedef struct {
    fp x, y, z;
} THREE_VECTOR;

typedef struct {
    fp v, x, y, z;
} FOUR_VECTOR;

typedef struct nei_str {
    int x, y, z;
    int number;
    long offset;
} nei_str;

typedef struct box_str {
    int x, y, z;
    int number;
    long offset;
    int nn;
    nei_str nei[26];
} box_str;

typedef struct par_str {
    fp alpha;
} par_str;

typedef struct dim_str {
    int cur_arg;
    int arch_arg;
    int cores_arg;
    int boxes1d_arg;
    long number_boxes;
    long box_mem;
    long space_elem;
    long space_mem;
    long space_mem2;
} dim_str;

// Inline timer implementation
static long long get_time_inline() {
    struct timeval tv;
    gettimeofday(&tv, NULL);
    return (tv.tv_sec * 1000000) + tv.tv_usec;
}

// Inline device utilities
static void setdevice_inline(void){
    int num_devices;
    int device;
    cudaGetDeviceCount(&num_devices);
    if (num_devices > 1) {
        int max_multiprocessors = 0;
        int max_device = 0;
        cudaDeviceProp properties;
        for (device = 0; device < num_devices; device++) {
            cudaGetDeviceProperties(&properties, device);
            if (max_multiprocessors < properties.multiProcessorCount) {
                max_multiprocessors = properties.multiProcessorCount;
                max_device = device;
            }
        }
        cudaSetDevice(max_device);
    }
}

static void checkCUDAError_inline(const char *msg) {
    cudaError_t err = cudaGetLastError();
    if( cudaSuccess != err) {
        printf("Cuda error: %s: %s.\n", msg, cudaGetErrorString( err) );
        fflush(NULL);
        exit(EXIT_FAILURE);
    }
}

__global__ void kernel_gpu(
    fp alpha,
    int number_boxes,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    int l = blockIdx.x;
    if (l >= number_boxes) return;

    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR* rA = &rv[first_i];
    FOUR_VECTOR* fA = &fv[first_i];

    // Process self-interaction (k=0, pointer=l)
    int pointer = l;
    long first_j = box[pointer].offset;
    FOUR_VECTOR* rB = &rv[first_j];
    fp* qB = &qv[first_j];

    for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
        FOUR_VECTOR fA_i = fA[i];
        FOUR_VECTOR rA_i = rA[i];

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            fp r2 = rA_i.v + rB[j].v - DOT(rA_i, rB[j]);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;

            THREE_VECTOR d;
            d.x = rA_i.x - rB[j].x;
            d.y = rA_i.y - rB[j].y;
            d.z = rA_i.z - rB[j].z;

            fp fxij = fs * d.x;
            fp fyij = fs * d.y;
            fp fzij = fs * d.z;

            fA_i.v += qB[j] * vij;
            fA_i.x += qB[j] * fxij;
            fA_i.y += qB[j] * fyij;
            fA_i.z += qB[j] * fzij;
        }
        fA[i] = fA_i;
    }

    // Process neighbors (k=1 to nn)
    for (int k = 1; k <= box[l].nn; k++) {
        pointer = box[l].nei[k-1].number;
        first_j = box[pointer].offset;
        rB = &rv[first_j];
        qB = &qv[first_j];

        for (int i = 0; i < NUMBER_PAR_PER_BOX; i++) {
            FOUR_VECTOR fA_i = fA[i];
            FOUR_VECTOR rA_i = rA[i];

            for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
                fp r2 = rA_i.v + rB[j].v - DOT(rA_i, rB[j]);
                fp u2 = a2 * r2;
                fp vij = exp(-u2);
                fp fs = 2.0 * vij;

                THREE_VECTOR d;
                d.x = rA_i.x - rB[j].x;
                d.y = rA_i.y - rB[j].y;
                d.z = rA_i.z - rB[j].z;

                fp fxij = fs * d.x;
                fp fyij = fs * d.y;
                fp fzij = fs * d.z;

                fA_i.v += qB[j] * vij;
                fA_i.x += qB[j] * fxij;
                fA_i.y += qB[j] * fyij;
                fA_i.z += qB[j] * fzij;
            }
            fA[i] = fA_i;
        }
    }
}

void kernel_cpu(
    par_str par,
    dim_str dim,
    box_str* box,
    FOUR_VECTOR* rv,
    fp* qv,
    FOUR_VECTOR* fv)
{
    long long time0 = get_time_inline();
    long long time1, time2, time3, time4;

    fp alpha = par.alpha;

    time1 = get_time_inline();

    setdevice_inline();
    time2 = get_time_inline();

    time3 = get_time_inline();

    // Allocate device memory
    box_str* d_box;
    FOUR_VECTOR* d_rv;
    fp* d_qv;
    FOUR_VECTOR* d_fv;

    cudaMalloc(&d_box, dim.box_mem);
    cudaMalloc(&d_rv, dim.space_mem);
    cudaMalloc(&d_qv, dim.space_mem2);
    cudaMalloc(&d_fv, dim.space_mem);

    cudaMemcpy(d_box, box, dim.box_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_rv, rv, dim.space_mem, cudaMemcpyHostToDevice);
    cudaMemcpy(d_qv, qv, dim.space_mem2, cudaMemcpyHostToDevice);
    cudaMemcpy(d_fv, fv, dim.space_mem, cudaMemcpyHostToDevice);

    // Launch kernel: one block per box
    kernel_gpu(alpha, dim.number_boxes, d_box, d_rv, d_qv, d_fv);
    checkCUDAError_inline("kernel_gpu launch");

    // Copy results back
    cudaMemcpy(fv, d_fv, dim.space_mem, cudaMemcpyDeviceToHost);

    cudaFree(d_box);
    cudaFree(d_rv);
    cudaFree(d_qv);
    cudaFree(d_fv);

    time4 = get_time_inline();

    printf("Time spent in different stages of CPU/MCPU KERNEL:\n");
    printf("%15.12f s, %15.12f % : CPU/MCPU: VARIABLES\n", 
           (float)(time1-time0) / 1000000, (float)(time1-time0) / (float)(time4-time0) * 100);
    printf("%15.12f s, %15.12f % : MCPU: SET DEVICE\n", 
           (float)(time2-time1) / 1000000, (float)(time2-time1) / (float)(time4-time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: INPUTS\n", 
           (float)(time3-time2) / 1000000, (float)(time3-time2) / (float)(time4-time0) * 100);
    printf("%15.12f s, %15.12f % : CPU/MCPU: KERNEL\n", 
           (float)(time4-time3) / 1000000, (float)(time4-time3) / (float)(time4-time0) * 100);

    printf("Total time:\n");
    printf("%.12f s\n", (float)(time4-time0) / 1000000);
}

#ifdef __cplusplus
}
#endif

